export type StartupControl = {
  label: string;
  value: string;
  type: 'enum' | 'slider' | 'toggle' | 'actions';
};

export type StartupDistrict = {
  id: string;
  name: string;
  role: string;
  asset: string;
  accent: string;
  x: string;
  y: string;
  population: string;
};

export type StartupFlow = {
  from: { x: number; y: number };
  to: { x: number; y: number };
  color: string;
  delay: string;
  duration: string;
  label: string;
};

export type TraceScore = {
  action: string;
  score: number;
};

export type StartupTrace = {
  agent: string;
  choice: string;
  summary: string;
  scores: TraceScore[];
  evidence: string[];
};

export type StartupSession = {
  id: string;
  title: string;
  subtitle: string;
  sessionId: string;
  tick: number;
  ticksTotal: number;
  deterministic: boolean;
  mode: string;
  controls: StartupControl[];
  metrics: {
    runway: string;
    runwayDelta: string;
    morale: string;
    moraleDelta: string;
    readiness: string;
    readinessDelta: string;
    headcount: string;
    headcountDelta: string;
  };
  world: {
    cashUsd: number;
    burnUsdPerTick: number;
    morale0100: number;
    stage: string;
    companies: number;
    investors: number;
    employees: number;
  };
  districts: StartupDistrict[];
  flows: StartupFlow[];
  traces: StartupTrace[];
  timeline: string[];
  signals: Array<{ label: string; value: string }>;
};

