export function getStartupSession(sessionId?: string): StartupSession {
  return startupSessions.find((session) => session.id === sessionId) ?? startupSessions[0];
}

export function buildTickReport(session: StartupSession) {
  return {
    session_id: session.sessionId,
    tick: session.tick,
    world: {
      mode: session.mode.split('/')[0].trim(),
      cash_usd: session.world.cashUsd,
      burn_usd_per_tick: session.world.burnUsdPerTick,
      morale_0_100: session.world.morale0100,
      stage: session.world.stage,
      district: {
        companies: session.world.companies,
        investors: session.world.investors,
        employees: session.world.employees,
      },
    },
    decision_traces: session.traces.length,
    tool_traces: session.traces.reduce((count, trace) => count + trace.evidence.length, 0),
    integrity: {
      valid: true,
      issues: [],
    },
  };
}
