import { promises as fs } from 'fs';
import path from 'path';

type LatestResult = {
  agent_class?: string;
  branch?: string;
  slice_id?: string;
  tests_passed?: boolean;
  decisiontrace_compliance?: boolean;
  tooltrace_compliance?: boolean;
  golden_seed_status?: string;
  blockers?: string[];
};

type MergeMarshalOutput = {
  ready_to_merge?: boolean;
  schemas_valid?: boolean;
  ui_no_free_text?: boolean;
  decision_trace_coverage?: boolean;
  blockers?: string[];
  next_commands?: string[];
};

export type RunArtifacts = {
  result: LatestResult | null;
  merge: MergeMarshalOutput | null;
};

async function readJsonFile<T>(filePath: string): Promise<T | null> {
  try {
    const raw = await fs.readFile(filePath, 'utf8');
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

export async function readRunArtifacts(): Promise<RunArtifacts> {
  const repoRoot = path.resolve(process.cwd(), '..', '..');
  const runsRoot = path.join(repoRoot, 'runs', 'latest');

  const [result, merge] = await Promise.all([
    readJsonFile<LatestResult>(path.join(runsRoot, 'result.json')),
    readJsonFile<MergeMarshalOutput>(path.join(runsRoot, 'merge-marshal-output.json')),
  ]);

  return { result, merge };
}
